@rendermode InteractiveServer
@using System.ComponentModel.DataAnnotations
@using sv_a1b8d3f1b1c944b5920f7339f644e3b9.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ===== STEP 1: Patient Information ===== *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="model.PatientName" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="model.Phone" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next: Select Appointment
            </button>
        }
    </fieldset>

    @* ===== STEP 2: Appointment Details ===== *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="model.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Date</label>
                <InputDate class="form-control" @bind-Value="model.AppointmentDate"
                           @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" @bind-Value="model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="button" class="btn btn-warning me-2" @onclick="CheckAvailability"
                    disabled="@isChecking">
                @(isChecking ? "Checking..." : "Check Availability")
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed || isSubmitting)">
                @(isSubmitting ? "Submitting..." : "Book Appointment")
            </button>
        </fieldset>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully for <strong>@model.PatientName</strong>
        with <strong>@model.Doctor</strong> on @model.AppointmentDate?.ToString("MMMM d, yyyy")
        at @model.TimeSlot.
    </div>
}

@code {
    private AppointmentFormModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isChecking;
    private bool isSubmitting;
    private bool availabilityConfirmed;
    private bool bookingConfirmed;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override void OnInitialized()
    {
        editContext = new EditContext(model);
    }

    private async Task ProceedToStep2()
    {
        customValidator?.ClearErrors();

        // Validate only step 1 fields
        var step1Valid = ValidateStep1();
        if (!step1Valid)
            return;

        doctors = await AppointmentService.GetDoctorsAsync();
        showStep2 = true;
        availabilityConfirmed = false;
    }

    private bool ValidateStep1()
    {
        var errors = new Dictionary<string, List<string>>();

        if (string.IsNullOrWhiteSpace(model.PatientName))
            errors[nameof(model.PatientName)] = ["Patient Name is required."];

        if (string.IsNullOrWhiteSpace(model.Email))
            errors[nameof(model.Email)] = ["Email is required."];
        else if (!new EmailAddressAttribute().IsValid(model.Email))
            errors[nameof(model.Email)] = ["Please enter a valid email address."];

        if (string.IsNullOrWhiteSpace(model.Phone))
            errors[nameof(model.Phone)] = ["Phone is required."];

        if (string.IsNullOrWhiteSpace(model.InsuranceProvider))
            errors[nameof(model.InsuranceProvider)] = ["Insurance Provider is required."];

        if (errors.Count > 0)
        {
            customValidator!.DisplayErrors(errors);
            return false;
        }

        return true;
    }

    private async Task OnDateChanged()
    {
        availableSlots = [];
        model.TimeSlot = "";
        availabilityConfirmed = false;

        if (model.AppointmentDate.HasValue && !string.IsNullOrEmpty(model.Doctor))
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityConfirmed = false;
        customValidator?.ClearErrors();
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityConfirmed = false;

        // Validate step 2 fields locally first
        var errors = new Dictionary<string, List<string>>();

        if (string.IsNullOrWhiteSpace(model.Doctor))
            errors[nameof(model.Doctor)] = ["Please select a doctor."];

        if (!model.AppointmentDate.HasValue)
            errors[nameof(model.AppointmentDate)] = ["Date is required."];
        else if (model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
            errors[nameof(model.AppointmentDate)] = ["Date must be in the future."];

        if (string.IsNullOrWhiteSpace(model.TimeSlot))
            errors[nameof(model.TimeSlot)] = ["Please select a time slot."];

        if (string.IsNullOrWhiteSpace(model.ReasonForVisit))
            errors[nameof(model.ReasonForVisit)] = ["Reason for visit is required."];
        else if (model.ReasonForVisit.Length > 500)
            errors[nameof(model.ReasonForVisit)] = ["Reason must be 500 characters or fewer."];

        if (errors.Count > 0)
        {
            customValidator!.DisplayErrors(errors);
            return;
        }

        // Server-side validation via AppointmentService
        isChecking = true;
        try
        {
            var serverErrors = await AppointmentService.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider, model.Doctor, model.TimeSlot);

            if (serverErrors.Count > 0)
            {
                customValidator!.DisplayErrors(serverErrors);
                return;
            }

            availabilityConfirmed = true;
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityConfirmed)
            return;

        isSubmitting = true;
        try
        {
            // Simulate booking delay
            await Task.Delay(500);
            bookingConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    // Local form model with no data annotations — validation is manual
    // to support two-step flow with selective field validation.
    private class AppointmentFormModel
    {
        public string? PatientName { get; set; }
        public string? Email { get; set; }
        public string? Phone { get; set; }
        public string InsuranceProvider { get; set; } = "";
        public string Doctor { get; set; } = "";
        public DateOnly? AppointmentDate { get; set; }
        public string TimeSlot { get; set; } = "";
        public string? ReasonForVisit { get; set; }
    }
}
"}

